import WidgetKit
import SwiftUI
import AppIntents
import RealityKit

struct CalendarIntent: AppIntent {
    static var title: LocalizedStringResource = 'Calendar'
    @Parameter(title: 'Calendar Style') var calendarStyle: String
}

struct CalendarWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: 'CalendarWidget',
            intent: CalendarIntent.self,
            provider: .static
        ) { entry in
            RealityView { content in
                if let model = try? await ModelEntity(named: entry.calendarStyle) {
                    content.add(model)
                }
            }
        }
    }
}

